prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org ?label ?modelCount WHERE {
  ?org a bboExt:Organization .
  ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  OPTIONAL { ?org rdfs:label ?label . }
  {
    SELECT ?org (COUNT(DISTINCT ?model) AS ?modelCount) WHERE {
      ?org a bboExt:Organization .
      ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
      ?model a bboExt:Model .
      ?model tai:belongsTo ?org .
    }
    GROUP BY ?org
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org ?label ?orgId ?modelCount WHERE {
  {
    SELECT ?org (COUNT(DISTINCT ?model) AS ?modelCount) WHERE {
      ?org a bboExt:Organization .
      ?model a bboExt:Model .
      ?model tai:belongsTo ?org .
    }
    GROUP BY ?org
    HAVING (COUNT(DISTINCT ?model) = 5)
  }
  OPTIONAL { ?org rdfs:label ?label . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
  FILTER NOT EXISTS {
    ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  }
}
ORDER BY ?label

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org ?label ?orgId ?modelCount WHERE {
  {
    SELECT ?org (COUNT(DISTINCT ?model) AS ?modelCount) WHERE {
      ?org a bboExt:Organization .
      ?model a bboExt:Model .
      ?model tai:belongsTo ?org .
    }
    GROUP BY ?org
  }
  {
    SELECT (COUNT(DISTINCT ?m) AS ?targetCount) WHERE {
      ?targetOrg a bboExt:Organization .
      ?targetOrg tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
      ?m a bboExt:Model .
      ?m tai:belongsTo ?targetOrg .
    }
  }
  FILTER(?modelCount = ?targetCount)
  FILTER NOT EXISTS {
    ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  }
  OPTIONAL { ?org rdfs:label ?label . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
}
ORDER BY ?label
